import React, { useState } from 'react';
import { FaTimes, FaSearchPlus, FaChevronLeft, FaChevronRight } from 'react-icons/fa';
import { Link } from 'gatsby';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Pagination, Autoplay } from 'swiper/modules';
import 'swiper/css';
import 'swiper/css/pagination';
import './gallery.css';

const galleryImages = [
  { id: 1, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img2.jpg', title: 'Wooden Fence Installation' },
  { id: 2, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img1.jpg', title: 'Fency Wooden Gate ' },
  { id: 3, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img3.jpg', title: 'Composite Fencing Installation' },
  { id: 4, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img4.jpg', title: 'Ornamental Iron Work' },
  { id: 5, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img5.jpg', title: 'Country Club Fencing' },
  { id: 6, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img6.jpg', title: 'White Vinyl Privacy' },
  { id: 7, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img7.jpg', title: 'Vinyl Privacy Fence' },
  { id: 8, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img8.jpg', title: 'Commercial Chain Link' },
  { id: 9, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img9.jpg', title: 'Gate Installation' },
  { id: 10, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img10.jpg', title: 'Classic Picket Detail' },
  { id: 11, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img11.jpg', title: 'Lattice Top Vinyl' },
  { id: 12, src: 'https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img12.jpg', title: 'Mixed Material Fencing' },
];

const Gallery: React.FC = () => {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  const openLightbox = (index: number) => {
    setCurrentImageIndex(index);
    setLightboxOpen(true);
    document.body.style.overflow = 'hidden';
  };

  const closeLightbox = () => {
    setLightboxOpen(false);
    document.body.style.overflow = 'unset';
  };

  const nextImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex((prev) => (prev + 1) % galleryImages.length);
  };

  const prevImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex((prev) => (prev - 1 + galleryImages.length) % galleryImages.length);
  };

  return (
    <section className="gallery-section" id="gallery">
      <div className="container">
        <div className="gallery-header">
          <div className="section-tag">
            <span>Our Portfolo</span>
          </div>
          <h2 className="gallery-title">A Legacy of <span className="highlight">Fencing Excellence</span></h2>
          <p className="gallery-subtitle">
            Explore some of our recently completed masterpieces. Our high-standard craftsmanship is consistent across every single project.
          </p>
        </div>

        {/* Desktop Masonry Grid */}
        <div className="masonry-grid desktop-only">
          {galleryImages.map((image, index) => (
            <div 
              key={image.id} 
              className="masonry-item" 
              onClick={() => openLightbox(index)}
            >
              <div className="gallery-card">
                <div className="gallery-img-wrapper">
                  <img src={image.src} alt={image.title} className="gallery-img" loading="lazy" />
                  <div className="gallery-overlay">
                    <FaSearchPlus className="zoom-icon" />
                    <div className="overlay-info">
                      <h3>{image.title}</h3>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Mobile Swiper Gallery */}
        <div className="mobile-only gallery-swiper-container">
          <Swiper
            modules={[Pagination, Autoplay]}
            spaceBetween={20}
            slidesPerView={1.2}
            centeredSlides={true}
            loop={true}
            autoplay={{ delay: 3500, disableOnInteraction: false }}
            pagination={{ clickable: true }}
            className="gallery-swiper"
          >
            {galleryImages.map((image, index) => (
              <SwiperSlide key={image.id} onClick={() => openLightbox(index)}>
                <div className="gallery-card mobile-card">
                  <div className="gallery-img-wrapper">
                    <img src={image.src} alt={image.title} className="gallery-img" />
                    <div className="mobile-overlay-info">
                       <h3>{image.title}</h3>
                    </div>
                  </div>
                </div>
              </SwiperSlide>
            ))}
          </Swiper>
        </div>

        <div className="load-more-container">
          <Link to="/projects" className="btn-load-more">View Full Projects Portal</Link>
        </div>
      </div>

      {/* Lightbox Overlay */}
      {lightboxOpen && (
        <div className="lightbox-overlay" onClick={closeLightbox}>
          <div className="lightbox-close" onClick={closeLightbox}>
            <FaTimes />
          </div>

          <div className="lightbox-nav-btn prev" onClick={prevImage}>
            <FaChevronLeft />
          </div>
          
          <div className="lightbox-content" onClick={(e) => e.stopPropagation()}>
            <img 
              src={galleryImages[currentImageIndex].src} 
              alt={galleryImages[currentImageIndex].title} 
              className="lightbox-main-img"
            />
            <div className="lightbox-caption">
              <h4>{galleryImages[currentImageIndex].title}</h4>
            </div>
          </div>

          <div className="lightbox-nav-btn next" onClick={nextImage}>
            <FaChevronRight />
          </div>
        </div>
      )}
    </section>
  );
};

export default Gallery;
